// BrowserWindow Configuration
const windowConfig = {
  width: 1200,
  height: 800,
  minWidth: 400,
  minHeight: 600,
  webPreferences: {
    contextIsolation: true,
    nodeIntegration: false,
    preload: 'electron/preload.js',
    sandbox: true,
    webSecurity: true,
  }
};

// URL Configuration
const DEV_URL = 'http://localhost:19006';
const PROD_URL = 'file://.../dist/index.html';

// Preload API (window.desktop)
interface DesktopAPI {
  versions: {
    node: string;
    chrome: string;
    electron: string;
    v8: string;
  };
  platform: {
    os: NodeJS.Platform;
    arch: string;
    isElectron: true;
  };
}

